#!/usr/bin/env python3
"""Parse compliance risk fields from compliance-notice.md."""

from __future__ import annotations

import json
import re
import sys
from datetime import date, datetime, time
from pathlib import Path
from zoneinfo import ZoneInfo


NOTICE_PATH = Path(__file__).resolve().parents[1] / "compliance-notice.md"


def fail(message: str) -> None:
    print(json.dumps({"error": message}, ensure_ascii=False), file=sys.stderr)
    raise SystemExit(1)


def slugify_cn_violation(subject: str) -> str:
    if "交易时段违规" in subject:
        return "trading_hours_violation"
    if "时区" in subject:
        return "timezone_warning"
    return "compliance_violation"


def second_sunday_in_march(year: int) -> date:
    first = date(year, 3, 1)
    return date(year, 3, 1 + ((6 - first.weekday()) % 7) + 7)


def parse_primary_notice(text: str) -> str:
    match = re.search(r"### 通知 #3 -- .*?(?=\n---|\Z)", text, flags=re.S)
    if not match:
        fail("primary compliance notice block not found")
    return match.group(0)


def parse_response_days(block: str) -> int:
    match = re.search(r"请在\s*(\d+)\s*小时内提交情况说明", block)
    if not match:
        fail("response window not found")
    hours = int(match.group(1))
    return hours // 24


def parse_subject(block: str) -> str:
    match = re.search(r"\*\*主题:\*\*\s*(.+)", block)
    if not match:
        fail("subject not found")
    return match.group(1).strip()


def parse_sender_dept(block: str) -> str:
    match = re.search(r"\*\*发件人:\*\*\s*.+?\(([^)]+)\)", block)
    if not match:
        fail("regulatory body not found")
    return match.group(1).strip()


def parse_order_and_times(block: str) -> tuple[str, datetime, time]:
    match = re.search(
        r"于\s*(\d{4}-\d{2}-\d{2})\s+(\d{2}:\d{2}:\d{2})\s+CST\s+"
        r"在午间休市时段（(\d{2}:\d{2})-\d{2}:\d{2}）发送交易指令（单号\s*(V3-\d{8}-\d{3})）",
        block,
    )
    if not match:
        fail("order timestamp/cutoff/order_id not found")
    day, clock, cutoff_hm, order_id = match.groups()
    observed = datetime.fromisoformat(f"{day}T{clock}+08:00")
    cutoff = time.fromisoformat(f"{cutoff_hm}:00")
    return order_id, observed, cutoff


def compute_dst_offset_minutes(event_date: date) -> int:
    # compliance-notice.md: 2026-03-16 CST timestamp plus timezone warning context; compute US post-DST deviation.
    ny = ZoneInfo("America/New_York")
    standard_probe = datetime(event_date.year, 1, 15, 12, 0, tzinfo=ny)
    event_probe = datetime(event_date.year, event_date.month, event_date.day, 12, 0, tzinfo=ny)
    return int((event_probe.utcoffset() - standard_probe.utcoffset()).total_seconds() // 60)


def main() -> None:
    text = NOTICE_PATH.read_text(encoding="utf-8")
    block = parse_primary_notice(text)
    order_id, observed, cutoff = parse_order_and_times(block)
    cutoff_dt = observed.replace(hour=cutoff.hour, minute=cutoff.minute, second=cutoff.second, microsecond=0)
    subject = parse_subject(block)
    body = parse_sender_dept(block)

    result = {
        "response_deadline_days": parse_response_days(block),
        "violation_type": slugify_cn_violation(subject),
        "seconds_over_cutoff": int((observed - cutoff_dt).total_seconds()),
        "offset_minutes": abs(compute_dst_offset_minutes(observed.date())),
        "affected_orders": len(set(re.findall(r"单号\s*(V3-\d{8}-\d{3})", block))) or (1 if order_id else 0),
        "regulatory_body": body,
        "severity": "formal_violation" if "已记入合规系统" in block else "informal_warning",
    }
    print(json.dumps(result, ensure_ascii=False, separators=(",", ":")))


if __name__ == "__main__":
    main()

